講解：[最長公共子序列 編輯距離【基礎演算法精講 19】](https://www.bilibili.com/video/BV1TM4y1o7ug/)

一般定義 `f[i][j]` 表示對 `(s[:i], t[:j])` 的求解結果。

```cpp
// 最長遞增子序列（二分優化 O(n log n)）
vector<int> tails;
for (int x : nums) {
    auto it = lower_bound(tails.begin(), tails.end(), x);
    if (it == tails.end()) {
        tails.push_back(x);
    } else {
        *it = x;
    }
}
// tails.size() 即 LIS 長度
```

「4. 經典線性 DP」的進階題：約束更緊、常與其他章節（堆、單調隊列、數學）拼裝。

**目標**：在模板之上能獨立完成建模與複雜度權衡。

**LCS 核心模板**：
`dp[i][j]` 表示 `s1[:i]` 與 `s2[:j]` 的 LCS 長度。

```cpp
// LCS：dp[i][j] = s[:i] 與 t[:j] 的最長公共子序列長度
vector<vector<int>> dp(m + 1, vector<int>(n + 1, 0));
for (int i = 1; i <= m; ++i) {
    for (int j = 1; j <= n; ++j) {
        if (s_1[i - 1] == s_2[j - 1]) {
            dp[i][j] = dp[i - 1][j - 1] + 1; // 字元相同，LCS 長度 +1
        } else {
            dp[i][j] = max(dp[i - 1][j], dp[i][j - 1]); // 字元不同，取較優子問題
        }
    }
}
```

```cpp
// 劃分型 DP 模板
// dp[i] 表示前 i 個元素的最優劃分結果
vector<int> dp(n + 1, INT_MAX);
dp[0] = 0;
for (int i = 1; i <= n; i++)
    for (int j = 0; j < i; j++)
        if (valid(j, i)) // 檢查 a[j..i-1] 是否為合法的一段
            dp[i] = min(dp[i], dp[j] + cost(j, i));
```

