```cpp
class Solution {
public:
    int countArrangement(int n) {
        int full = 1 << n;
        vector<int> dp(full);
        dp[0] = 1;
        for (int mask = 0; mask < full; ++mask) {
            int pos = __builtin_popcount((unsigned)mask) + 1;
            for (int i = 1; i <= n; ++i) {
                if (mask >> (i - 1) & 1) continue;
                if (i % pos == 0 || pos % i == 0) dp[mask | (1 << (i - 1))] += dp[mask];
            }
        }
        return dp[full - 1];
    }
};
```

