class Solution {
public:
    pair<int,int> dfs(TreeNode* root) {
        if (!root) return {0, 0};
        auto [l0, l1] = dfs(root->left);
        auto [r0, r1] = dfs(root->right);
        int skip = max(l0, l1) + max(r0, r1);
        int take = root->val + l0 + r0;
        return {skip, take};
    }
    int rob(TreeNode* root) {
        auto [skip, take] = dfs(root);
        return max(skip, take);
    }
};
```

